BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?name ?owner ?ownerName WHERE {
  ?pkg vocab:NamedElement_name "Black%20Box%20Specification" .
  ?pkg rdf:type vocab:package .
  OPTIONAL { ?pkg vocab:Element_owner ?owner . ?owner vocab:NamedElement_name ?ownerName }
  OPTIONAL { ?pkg vocab:Package_nestingPackage ?nesting . ?nesting vocab:NamedElement_name ?nestingName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?owner ?ownerName WHERE {
  ?elem <http://api.koneksys.com/cameo/vocab/NamedElement_name> "Black%20Box%20Specification" .
  FILTER(CONTAINS(STR(?elem), "Alignment%20and%20Phasing%20System")) .
  ?elem rdf:type vocab:package .
  OPTIONAL { ?elem vocab:Element_owner ?owner . ?owner vocab:NamedElement_name ?ownerName }
}
LIMIT 25

