BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?child ?childName ?type WHERE {
  BIND(<http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS> as ?aps)
  { ?aps vocab:Package_packagedElement ?child }
  UNION
  { ?aps vocab:Package_nestedPackage ?child }
  ?child vocab:NamedElement_name ?childName .
  ?child rdf:type ?type .
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?parent ?parentName ?grandparent ?grandparentName WHERE {
