  ?aps vocab:Element_owner ?parent .
  ?parent vocab:NamedElement_name ?parentName .
  OPTIONAL {
    ?parent vocab:Element_owner ?grandparent .
    ?grandparent vocab:NamedElement_name ?grandparentName .
  }
